        except Exception:
            sha = None
    inputs.append({
        'logical_path': rp['logical_path'],
        'resolved_path': path,
        'exists': exists,
        'size_bytes': size,
        'sha256': sha,
        'schema_summary': infer_schema_summary(path, size) if exists else None
    })

outputs = []
for wp in write_paths:
